# Target root folder inside your workspace$root = "C:\Users\armando\Documents\_AHS\projects\AHS.SaaS\dotnet10-rag"# Create root directoryNew-Item -ItemType Directory -Path $root -Force | Out-Null# Helper function to create filesfunction Write-File($path, $content) {    $folder = Split-Path $path    if (!(Test-Path $folder)) {        New-Item -ItemType Directory -Path $folder -Force | Out-Null    }    Set-Content -Path $path -Value $content -Encoding UTF8}# -------------------------# 00-Index# -------------------------Write-File "$root\00-Index\index.md" @"# .NET 10 RAG Dataset — Navigation IndexThis dataset contains structured, chunk-ready documentation for the major components of .NET 10.Excluded technologies: Visual Basic, F#, Windows Forms, WPF, and Windows-specific MAUI APIs.## 1. Runtime- JIT- GC- NativeAOT- Performance## 2. Libraries- Networking- Collections- Numerics- Security## 3. SDK- CLI- Containers- AOT- Tooling## 4. C# 14- field keyword- Extension blocks- Null-conditional assignment- Language enhancements## 5. ASP.NET Core- Hosting- Minimal APIs- Blazor- Authentication- Performance## 6. EF Core- Performance- Interceptors- Mapping- Tooling## 7. Aspire- Components- Orchestration- Observability## 8. MAUI (Cross-platform only)- UI- Handlers- Shell- Essentials- Performance"@# -------------------------# 01-Runtime# -------------------------Write-File "$root\01-Runtime\overview.md" @"# .NET 10 Runtime — OverviewThe .NET 10 runtime introduces performance improvements, expanded hardware support, and enhancements to the JIT, GC, and NativeAOT toolchain."@Write-File "$root\01-Runtime\jit.md" @"# JIT Improvements in .NET 10The JIT compiler in .NET 10 delivers better throughput and more aggressive optimizations."@Write-File "$root\01-Runtime\nativeaot.md" @"# NativeAOT in .NET 10NativeAOT continues to mature in .NET 10, offering smaller binaries and faster startup times."@Write-File "$root\01-Runtime\gc.md" @"# Garbage Collection Improvements in .NET 10The GC in .NET 10 focuses on reducing latency and improving memory efficiency."@Write-File "$root\01-Runtime\performance.md" @"# Runtime Performance in .NET 10.NET 10 delivers broad performance improvements across the runtime."@# -------------------------# 02-Libraries# -------------------------Write-File "$root\02-Libraries\overview.md" @"# .NET 10 Libraries — OverviewThe .NET 10 libraries introduce improvements across networking, collections, numerics, and security."@Write-File "$root\02-Libraries\networking.md" @"# Networking Improvements in .NET 10HTTP/3, sockets, and TLS improvements enhance performance and reliability."@Write-File "$root\02-Libraries\collections.md" @"# Collections Improvements in .NET 10Faster dictionary lookups, reduced memory usage, and improved LINQ performance."@Write-File "$root\02-Libraries\numerics.md" @"# Numerics in .NET 10SIMD improvements and faster BigInteger operations."@Write-File "$root\02-Libraries\security.md" @"# Security Enhancements in .NET 10Cryptography and authentication improvements."@# -------------------------# 03-SSDK# -------------------------Write-File "$root\03-SDK\overview.md" @"# .NET 10 SDK — OverviewThe .NET 10 SDK introduces improvements to the CLI, container tooling, AOT workflows, and developer productivity."@Write-File "$root\03-SDK\cli.md" @"# CLI Improvements in .NET 10Faster restore, improved templates, and better diagnostics."@Write-File "$root\03-SDK\containers.md" @"# Container Tooling in .NET 10Smaller base images and faster publish-to-container workflows."@Write-File "$root\03-SDK\aot.md" @"# AOT Tooling in .NET 10Faster compilation, better trimming, and improved error reporting."@Write-File "$root\03-SDK\tooling.md" @"# Tooling Enhancements in .NET 10Better IDE support and faster incremental builds."@# -------------------------# 04-CSharp14# -------------------------Write-File "$root\04-CSharp14\overview.md" @"# C# 14 — OverviewC# 14 introduces language features designed to reduce ceremony and improve clarity."@Write-File "$root\04-CSharp14\field-keyword.md" @"# The `field` Keyword in C# 14Allows direct access to the backing field of an auto-property."@Write-File "$root\04-CSharp14\extension-blocks.md" @"# Extension Blocks in C# 14Groups extension members under a single scope."@Write-File "$root\04-CSharp14\null-conditional-assignment.md" @"# Null-Conditional Assignment in C# 14Assign only when the target is non-null."@Write-File "$root\04-CSharp14\language-enhancements.md" @"# Additional Language Enhancements in C# 14Pattern matching, lambda improvements, and reduced ceremony."@# -------------------------# 05-ASPNETCore# -------------------------Write-File "$root\05-ASPNETCore\overview.md" @"# ASP.NET Core in .NET 10 — OverviewASP.NET Core in .NET 10 focuses on performance, simplified hosting, and improved developer experience."@Write-File "$root\05-ASPNETCore\hosting.md" @"# Hosting Improvements in ASP.NET CoreFaster startup, simplified configuration, and better diagnostics."@Write-File "$root\05-ASPNETCore\minimal-apis.md" @"# Minimal APIs in .NET 10Better routing, validation, and parameter binding."@Write-File "$root\05-ASPNETCore\blazor.md" @"# Blazor in .NET 10Faster rendering, better interactivity, and reduced memory usage."@Write-File "$root\05-ASPNETCore\authentication.md" @"# Authentication in ASP.NET Core 10Improved token validation and identity provider integration."@Write-File "$root\05-ASPNETCore\performance.md" @"# ASP.NET Core Performance in .NET 10Reduced allocations, faster JSON serialization, and better Kestrel throughput."@# -------------------------# 06-EFCore# -------------------------Write-File "$root\06-EFCore\overview.md" @"# EF Core in .NET 10 — OverviewEF Core 10 introduces performance improvements, better interceptors, and enhanced mapping."@Write-File "$root\06-EFCore\performance.md" @"# EF Core Performance ImprovementsFaster queries, reduced memory usage, and better batching."@Write-File "$root\06-EFCore\interceptors.md" @"# EF Core Interceptors in .NET 10More granular interception points and better diagnostics."@Write-File "$root\06-EFCore\mapping.md" @"# Mapping Improvements in EF Core 10Better TPH performance and improved owned types."@Write-File "$root\06-EFCore\tooling.md" @"# EF Core Tooling in .NET 10Faster migrations and improved scaffolding."@# -------------------------# 07-Aspire# -------------------------Write-File "$root\07-Aspire\overview.md" @"# .NET Aspire — OverviewOpinionated orchestration, components, and observability for cloud-native .NET applications."@Write-File "$root\07-Aspire\components.md" @"# Aspire ComponentsPrebuilt service components and simplified configuration."@Write-File "$root\07-Aspire\orchestration.md" @"# Aspire OrchestrationDeclarative service composition and environment provisioning."@Write-File "$root\07-Aspire\observability.md" @"# Aspire ObservabilityDistributed tracing, metrics, and logging integration."@# -------------------------# 08-MAUI (Cross-platform only)# -------------------------Write-File "$root\08-MAUI\overview.md" @"# .NET MAUI — Cross-Platform OverviewThis section covers only the cross-platform aspects of .NET MAUI."@Write-File "$root\08-MAUI\cross-platform-ui.md" @"# Cross-Platform UI in MAUIUnified XAML UI, shared layouts, and native controls."@Write-File "$root\08-MAUI\handlers-common.md" @"# Common Handlers in MAUICross-platform control handlers with consistent behavior."@Write-File "$root\08-MAUI\shell.md" @"# MAUI ShellUnified navigation model with flyouts and tabs."@Write-File "$root\08-MAUI\essentials.md" @"# MAUI EssentialsSensors, connectivity, device info, and secure storage."@Write-File "$root\08-MAUI\performance.md" @"# MAUI Performance in .NET 10Faster startup, reduced memory usage, and better handler performance."@# -------------------------# metadata.json# -------------------------Write-File "$root\metadata.json" @"{  `"dataset`": `"dotnet10-rag`",  `"version`": `"1.0`",  `"language`": `"en`",  `"excluded_sections`": [    `"Visual Basic`",    `"F#`",    `"Windows Forms`",    `"WPF`",    `"MAUI Windows-specific`"  ],  `"included_sections`": [    `"Runtime`",    `"Libraries`",    `"SDK`",    `"C# 14`",    `"ASP.NET Core`",    `"EF Core`",    `"Aspire`",    `"Containers`",    `"NativeAOT`",    `"MAUI Cross-platform`",    `"Tooling`",    `"Performance`"  ],  `"chunking`": {    `"size_tokens`": 1000,    `"overlap_tokens`": 150,    `"method`": `"semantic + structural`"  }}"@